# 输入获取
k = int(input())
s = input()


# 算法入口
def getResult(k, s):
    stack = []
    res = []

    for c in s:
        if c == '_' and (len(stack) == 0 or stack[0] != '"'):
            res.append("".join(stack))
            stack = []
        elif c == '"' and len(stack) != 0:
            stack.append(c)
            res.append("".join(stack))
            stack = []
        else:
            stack.append(c)

    if len(stack) > 0:
        res.append("".join(stack))

    ans = list(filter(lambda x: x != "", res))

    if k > len(ans) - 1:
        return "ERROR"

    ans[k] = "******"

    return "_".join(ans)


# 算法调用
print(getResult(k, s))
